<?php
namespace App\Services\Customers; use App\Models\Customers\Customer; use App\Models\Customers\CustomerGroup; use App\Repositories\Customers\CustomerDashboardRepository; use App\Repositories\Customers\CustomerRepository;
class CustomerDashboardService { public function __construct(private readonly CustomerDashboardRepository $dashboard,private readonly CustomerRepository $customers){} /** @return array<string,mixed> */ public function data(int $companyId):array{$settings=$this->dashboard->settings($companyId);$customers=Customer::query()->where('company_id',$companyId);$birthdays=$this->dashboard->birthdays($companyId,$settings->birthday_reminder_days_before);$inactive=$this->dashboard->flagged($companyId,'is_inactive_90_days');$lost=$this->dashboard->flagged($companyId,'is_lost_customer');$returns=$this->dashboard->flagged($companyId,'is_frequent_returner');return ['settings'=>$settings,'cards'=>['total'=>$customers->count(),'active'=>(clone $customers)->where('status','active')->count(),'new_month'=>(clone $customers)->where('created_at','>=',now()->startOfMonth())->count(),'vip'=>(clone $customers)->whereIn('customer_type',['vip','corporate'])->count(),'loyalty'=>(clone $customers)->whereHas('loyaltyAccount')->count(),'wallet'=>(clone $customers)->sum('wallet_balance'),'birthdays'=>$birthdays->count(),'inactive'=>$inactive->count(),'lost'=>$lost->count(),'returns'=>$returns->count(),'top_value'=>(clone $customers)->max('total_purchase_amount')??0,'return_risk'=>$returns->count()],'top'=>$this->customers->top($companyId),'birthdays'=>$birthdays,'inactive'=>$inactive->take(8),'lost'=>$lost->take(8),'returns'=>$returns->take(8),'segments'=>['New'=>(clone $customers)->where('created_at','>=',now()->subDays(30))->count(),'Active'=>(clone $customers)->where('status','active')->count(),'VIP'=>(clone $customers)->where('customer_type','vip')->count(),'Wholesale'=>(clone $customers)->where('customer_type','wholesale')->count(),'Inactive'=>$inactive->count(),'Lost'=>$lost->count(),'Frequent returner'=>$returns->count(),'Loyalty member'=>(clone $customers)->whereHas('loyaltyAccount')->count()]];} }
